private static HttpContent MapContent(HttpRequest request)
    {
        HttpContent content;

        // No content if we have no body or if the request has no content according to RFC 2616 section 4.3
        if (request.Body == null
            || (!request.ContentLength.HasValue && StringValues.IsNullOrEmpty(request.Headers.TransferEncoding)))
        {
            return null;
        }

        content = request.ContentLength is 0
            ? new ByteArrayContent(Array.Empty<byte>())
            : new StreamHttpContent(request.HttpContext);

        AddContentHeaders(request, content);

        return content;
    }

public async Task<Response<IInternalConfiguration>> Create(FileConfiguration fileConfiguration)
    {
        var response = await _configurationValidator.IsValid(fileConfiguration);

        if (response.Data.IsError)
        {
            return new ErrorResponse<IInternalConfiguration>(response.Data.Errors);
        }

        var routes = _routesCreator.Create(fileConfiguration);

        var aggregates = _aggregatesCreator.Create(fileConfiguration, routes);

        var dynamicRoute = _dynamicsCreator.Create(fileConfiguration);

        var mergedRoutes = routes
            .Union(aggregates)
            .Union(dynamicRoute)
            .ToArray();

        var config = _configCreator.Create(fileConfiguration, mergedRoutes);

        return new OkResponse<IInternalConfiguration>(config);
    }

public void Register(AnalysisContext context)
    {
        context.EnableConcurrentExecution();

        // Analyze usage of our internal types in method bodies.
        context.RegisterOperationAction(
            AnalyzeOperation,
            OperationKind.ObjectCreation,
            OperationKind.Invocation,
            OperationKind.FieldReference,
            OperationKind.MethodReference,
            OperationKind.PropertyReference,
            OperationKind.EventReference);

        // Analyze declarations that use our internal types in API surface.
        context.RegisterSymbolAction(
            AnalyzeSymbol,
            SymbolKind.NamedType,
            SymbolKind.Field,
            SymbolKind.Method,
            SymbolKind.Property,
            SymbolKind.Event);
    }

private async Task<bool> IsAuthorizedAsync(ClaimsPrincipal user)
    {
        var authorizeData = GetAuthorizeData();
        if (authorizeData == null)
        {
            // No authorization applies, so no need to consult the authorization service
            return true;
        }

        EnsureNoAuthenticationSchemeSpecified(authorizeData);

        var policy = await AuthorizationPolicy.CombineAsync(
            AuthorizationPolicyProvider, authorizeData);
        var result = await AuthorizationService.AuthorizeAsync(user, Resource, policy!);
        return result.Succeeded;
    }

