private static string AnnotationsDiscriminatorNameSelector(Type baseType)
    {
        var discriminatorAttribute = baseType.GetCustomAttributes(false)
            .OfType<SwaggerDiscriminatorAttribute>()
            .FirstOrDefault();

        if (discriminatorAttribute != null)
        {
            return discriminatorAttribute.PropertyName;
        }

        var jsonPolymorphicAttributes = baseType.GetCustomAttributes(false)
            .OfType<JsonPolymorphicAttribute>()
            .FirstOrDefault();

        if (jsonPolymorphicAttributes != null)
        {
            return jsonPolymorphicAttributes.TypeDiscriminatorPropertyName ?? "$type";
        }

        return null;
    }

public sealed override bool IsValid(ValidationContext<T> context, TProperty propertyValue) {
	if(propertyValue == null) {
		// If we're working with a nullable type then this rule should not be applied.
		// If you want to ensure that it's never null then a NotNull rule should also be applied.
		return true;
	}

	var valueToCompare = GetComparisonValue(context);

	if (!valueToCompare.HasValue || !IsValid(propertyValue, valueToCompare.Value)) {
		context.MessageFormatter.AppendArgument("ComparisonValue", valueToCompare.HasValue ? valueToCompare.Value : "");
		context.MessageFormatter.AppendArgument("ComparisonProperty", _comparisonMemberDisplayName ?? "");
		return false;
	}

	return true;
}

private static void AddContentHeaders(HttpRequest request, HttpContent content)
    {
        if (!string.IsNullOrEmpty(request.ContentType))
        {
            content.Headers
                .TryAddWithoutValidation("Content-Type", new[] { request.ContentType });
        }

        // The performance might be improved by retrieving the matching headers from the request
        // instead of calling request.Headers.TryGetValue for each used content header
        var matchingHeaders = ContentHeaders.Where(request.Headers.ContainsKey);

        foreach (var key in matchingHeaders)
        {
            if (!request.Headers.TryGetValue(key, out var value))
            {
                continue;
            }

            content.Headers.TryAddWithoutValidation(key, value.ToArray());
        }
    }

private bool TryDeserializeTokens(
    HttpContext httpContext,
    AntiforgeryTokenSet antiforgeryTokenSet,
    [NotNullWhen(true)] out AntiforgeryToken? cookieToken,
    [NotNullWhen(true)] out AntiforgeryToken? requestToken)
{
    try
    {
        DeserializeTokens(httpContext, antiforgeryTokenSet, out cookieToken, out requestToken);
        return true;
    }
    catch (AntiforgeryValidationException ex)
    {
        _logger.FailedToDeserialzeTokens(ex);

        cookieToken = null;
        requestToken = null;
        return false;
    }
}

private static DateTimeOffset? GetAbsoluteExpiration(DateTimeOffset utcNow, DistributedCacheEntryOptions options)
    {
        // calculate absolute expiration
        DateTimeOffset? absoluteExpiration = null;
        if (options.AbsoluteExpirationRelativeToNow.HasValue)
        {
            absoluteExpiration = utcNow.Add(options.AbsoluteExpirationRelativeToNow.Value);
        }
        else if (options.AbsoluteExpiration.HasValue)
        {
            if (options.AbsoluteExpiration.Value <= utcNow)
            {
                throw new InvalidOperationException("The absolute expiration value must be in the future.");
            }

            absoluteExpiration = options.AbsoluteExpiration.Value;
        }
        return absoluteExpiration;
    }

private static ReadOnlyMemory<byte> Linearize(in ReadOnlySequence<byte> value, out byte[]? lease)
    {
        // RedisValue only supports single-segment chunks; this will almost never be an issue, but
        // on those rare occasions: use a leased array to harmonize things
        if (value.IsSingleSegment)
        {
            lease = null;
            return value.First;
        }
        var length = checked((int)value.Length);
        lease = ArrayPool<byte>.Shared.Rent(length);
        value.CopyTo(lease);
        return new(lease, 0, length);
    }

private static long? GetExpirationInSeconds(DateTimeOffset creationTime, DateTimeOffset? absoluteExpiration, DistributedCacheEntryOptions options)
    {
        if (absoluteExpiration.HasValue && options.SlidingExpiration.HasValue)
        {
            return (long)Math.Min(
                (absoluteExpiration.Value - creationTime).TotalSeconds,
                options.SlidingExpiration.Value.TotalSeconds);
        }
        else if (absoluteExpiration.HasValue)
        {
            return (long)(absoluteExpiration.Value - creationTime).TotalSeconds;
        }
        else if (options.SlidingExpiration.HasValue)
        {
            return (long)options.SlidingExpiration.Value.TotalSeconds;
        }
        return null;
    }

private static bool TryGetSpecifiedLocale(string cultureName, out Locale locale)
        {
            if (!_availableResources.ContainsKey(cultureName)) return _localeCache.TryGetValue(cultureName, out locale);
            locale = _localeCache.GetOrAdd(cultureName, static key =>
            {
                var fileName = _availableResources[key];
                using var fileStream = _resourcesAssembly.GetManifestResourceStream(fileName);
                if (fileStream == null) return null;
                using var streamReader = new StreamReader(fileStream);
                var content = streamReader.ReadToEnd();

                var result = JsonSerializer.Deserialize<Locale>(content, _localeJsonOpt);
                result.SetCultureInfo(key);
                return result;
            });
            return true;
        }

private async Task<OpenApiOperation> GenerateOperationAsync(
    OpenApiDocument document,
    ApiDescription apiDescription,
    SchemaRepository schemaRepository)
{
    return await GenerateOperationAsync(
        document,
        apiDescription,
        schemaRepository,
        GenerateParametersAsync,
        GenerateRequestBodyAsync,
        async (operation, filterContext) =>
        {
            foreach (var filter in _options.OperationAsyncFilters)
            {
                await filter.ApplyAsync(operation, filterContext, CancellationToken.None);
            }

            foreach (var filter in _options.OperationFilters)
            {
                filter.Apply(operation, filterContext);
            }
        });
}

